const { chmodSync, mkdirSync, mkdtempSync, rmSync } = require("node:fs");
const { tmpdir } = require("node:os");
const path = require("node:path");
const { spawnSync } = require("node:child_process");

const root = mkdtempSync(path.join(tmpdir(), "npm-global-denial-"));
const prefix = path.join(root, "prefix");
mkdirSync(prefix, { recursive: true });
chmodSync(prefix, 0o555);

const npm = process.platform === "win32" ? "npm.cmd" : "npm";
const result = spawnSync(npm, ["install", "--global", ".", "--prefix", prefix], {
  cwd: __dirname,
  stdio: "inherit"
});

chmodSync(prefix, 0o755);
rmSync(root, { recursive: true, force: true });
process.exit(result.status ?? 1);

